4087	static bool ContextualCheckBlockHeader(const CBlockHeader& block, BlockValidationState& state, const ChainstateManager& chainman, const CBlockIndex* pindexPrev) EXCLUSIVE_LOCKS_REQUIRED(::cs_main)
4088	{
4089	    AssertLockHeld(::cs_main);
4090	    assert(pindexPrev != nullptr);
4091	    const int nHeight = pindexPrev->nHeight + 1;
4092	
4093	    // Check proof of work
4094	    const Consensus::Params& consensusParams = chainman.GetConsensus();
4095	    if (block.nBits != GetNextWorkRequired(pindexPrev, &block, consensusParams))
4096	        return state.Invalid(BlockValidationResult::BLOCK_INVALID_HEADER, "bad-diffbits", "incorrect proof of work");
4097	
4098	    // Check timestamp against prev
4099	    if (block.GetBlockTime() <= pindexPrev->GetMedianTimePast())
4100	        return state.Invalid(BlockValidationResult::BLOCK_INVALID_HEADER, "time-too-old", "block's timestamp is too early");
4101	
4102	    // Testnet4 and regtest only: Check timestamp against prev for difficulty-adjustment
4103	    // blocks to prevent timewarp attacks (see https://github.com/bitcoin/bitcoin/pull/15482).
4104	    if (consensusParams.enforce_BIP94) {
4105	        // Check timestamp for the first block of each difficulty adjustment
4106	        // interval, except the genesis block.
4107	        if (nHeight % consensusParams.DifficultyAdjustmentInterval() == 0) {
4108	            if (block.GetBlockTime() < pindexPrev->GetBlockTime() - MAX_TIMEWARP) {
4109	                return state.Invalid(BlockValidationResult::BLOCK_INVALID_HEADER, "time-timewarp-attack", "block's timestamp is too early on diff adjustment block");
4110	            }
4111	        }
4112	    }
4113	
4114	    // Check timestamp
4115	    if (block.Time() > NodeClock::now() + std::chrono::seconds{MAX_FUTURE_BLOCK_TIME}) {
4116	        return state.Invalid(BlockValidationResult::BLOCK_TIME_FUTURE, "time-too-new", "block timestamp too far in the future");
4117	    }
4118	
4119	    // Reject blocks with outdated version
4120	    if ((block.nVersion < 2 && DeploymentActiveAfter(pindexPrev, chainman, Consensus::DEPLOYMENT_HEIGHTINCB)) ||
4121	        (block.nVersion < 3 && DeploymentActiveAfter(pindexPrev, chainman, Consensus::DEPLOYMENT_DERSIG)) ||
4122	        (block.nVersion < 4 && DeploymentActiveAfter(pindexPrev, chainman, Consensus::DEPLOYMENT_CLTV))) {
4123	            return state.Invalid(BlockValidationResult::BLOCK_INVALID_HEADER, strprintf("bad-version(0x%08x)", block.nVersion),
4124	                                 strprintf("rejected nVersion=0x%08x block", block.nVersion));
4125	    }
4126	
4127	    return true;
4128	}
