4136	static bool ContextualCheckBlock(const CBlock& block, BlockValidationState& state, const ChainstateManager& chainman, const CBlockIndex* pindexPrev)
4137	{
4138	    const int nHeight = pindexPrev == nullptr ? 0 : pindexPrev->nHeight + 1;
4139	
4140	    // Enforce BIP113 (Median Time Past).
4141	    bool enforce_locktime_median_time_past{false};
4142	    if (DeploymentActiveAfter(pindexPrev, chainman, Consensus::DEPLOYMENT_CSV)) {
4143	        assert(pindexPrev != nullptr);
4144	        enforce_locktime_median_time_past = true;
4145	    }
4146	
4147	    const int64_t nLockTimeCutoff{enforce_locktime_median_time_past ?
4148	                                      pindexPrev->GetMedianTimePast() :
4149	                                      block.GetBlockTime()};
4150	
4151	    // Check that all transactions are finalized
4152	    for (const auto& tx : block.vtx) {
4153	        if (!IsFinalTx(*tx, nHeight, nLockTimeCutoff)) {
4154	            return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-txns-nonfinal", "non-final transaction");
4155	        }
4156	    }
4157	
4158	    // Enforce rule that the coinbase starts with serialized block height
4159	    if (DeploymentActiveAfter(pindexPrev, chainman, Consensus::DEPLOYMENT_HEIGHTINCB))
4160	    {
4161	        CScript expect = CScript() << nHeight;
4162	        if (block.vtx[0]->vin[0].scriptSig.size() < expect.size() ||
4163	            !std::equal(expect.begin(), expect.end(), block.vtx[0]->vin[0].scriptSig.begin())) {
4164	            return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-cb-height", "block height mismatch in coinbase");
4165	        }
4166	    }
4167	
4168	    // Validation for witness commitments.
4169	    // * We compute the witness hash (which is the hash including witnesses) of all the block's transactions, except the
4170	    //   coinbase (where 0x0000....0000 is used instead).
4171	    // * The coinbase scriptWitness is a stack of a single 32-byte vector, containing a witness reserved value (unconstrained).
4172	    // * We build a merkle tree with all those witness hashes as leaves (similar to the hashMerkleRoot in the block header).
4173	    // * There must be at least one output whose scriptPubKey is a single 36-byte push, the first 4 bytes of which are
4174	    //   {0xaa, 0x21, 0xa9, 0xed}, and the following 32 bytes are SHA256^2(witness root, witness reserved value). In case there are
4175	    //   multiple, the last one is used.
4176	    if (!CheckWitnessMalleation(block, DeploymentActiveAfter(pindexPrev, chainman, Consensus::DEPLOYMENT_SEGWIT), state)) {
4177	        return false;
4178	    }
4179	
4180	    // After the coinbase witness reserved value and commitment are verified,
4181	    // we can check if the block weight passes (before we've checked the
4182	    // coinbase witness, it would be possible for the weight to be too
4183	    // large by filling up the coinbase witness, which doesn't change
4184	    // the block hash, so we couldn't mark the block as permanently
4185	    // failed).
4186	    if (GetBlockWeight(block) > MAX_BLOCK_WEIGHT) {
4187	        return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-blk-weight", strprintf("%s : weight limit failed", __func__));
4188	    }
4189	
4190	    return true;
4191	}
