4209	                                     strprintf("block %s was previously marked invalid", hash.ToString()));
4210	            }
4211	            return true;
4212	        }
4213	
4214	        if (!CheckBlockHeader(block, state, GetConsensus())) {
4215	            LogDebug(BCLog::VALIDATION, "%s: Consensus::CheckBlockHeader: %s, %s\n", __func__, hash.ToString(), state.ToString());
4216	            return false;
4217	        }
4218	
4219	        // Get prev block index
4220	        CBlockIndex* pindexPrev = nullptr;
4221	        BlockMap::iterator mi{m_blockman.m_block_index.find(block.hashPrevBlock)};
4222	        if (mi == m_blockman.m_block_index.end()) {
4223	            LogDebug(BCLog::VALIDATION, "header %s has prev block not found: %s\n", hash.ToString(), block.hashPrevBlock.ToString());
4224	            return state.Invalid(BlockValidationResult::BLOCK_MISSING_PREV, "prev-blk-not-found");
4225	        }
4226	        pindexPrev = &((*mi).second);
4227	        if (pindexPrev->nStatus & BLOCK_FAILED_VALID) {
4228	            LogDebug(BCLog::VALIDATION, "header %s has prev block invalid: %s\n", hash.ToString(), block.hashPrevBlock.ToString());
4229	            return state.Invalid(BlockValidationResult::BLOCK_INVALID_PREV, "bad-prevblk");
4230	        }
4231	        if (!ContextualCheckBlockHeader(block, state, *this, pindexPrev)) {
4232	            LogDebug(BCLog::VALIDATION, "%s: Consensus::ContextualCheckBlockHeader: %s, %s\n", __func__, hash.ToString(), state.ToString());
4233	            return false;
4234	        }
4235	    }
4236	    if (!min_pow_checked) {
4237	        LogDebug(BCLog::VALIDATION, "%s: not adding new block header %s, missing anti-dos proof-of-work validation\n", __func__, hash.ToString());
4238	        return state.Invalid(BlockValidationResult::BLOCK_HEADER_LOW_WORK, "too-little-chainwork");
4239	    }
